/**
 * @name Taint flow from JDBC URL to Runtime.exec
 * @description Check if JDBC connection URL parameters can reach Runtime.exec()
 * @kind path-problem
 * @problem.severity error
 * @id java/jdbc-url-to-exec
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JdbcExecConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // JDBC URL / connection properties as source
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getURL") or
        mc.getMethod().hasName("getProperty") or
        mc.getMethod().hasName("getParameter") or
        mc.getMethod().hasName("connect") or
        mc.getMethod().hasName("acceptsURL")
      ) and
      source.asExpr() = mc
    )
    or
    // Method parameters named url or fileName
    exists(Parameter p |
      (p.getName() = "url" or p.getName() = "fileName" or p.getName() = "path") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module JdbcExecFlow = TaintTracking::Global<JdbcExecConfig>;
import JdbcExecFlow::PathGraph

from JdbcExecFlow::PathNode source, JdbcExecFlow::PathNode sink
where JdbcExecFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential command injection: data from $@ reaches Runtime.exec().", source.getNode(), "JDBC URL/parameter"

/**
 * @name Full taint trace from JDBC connection URL to System.load native library
 * @description Trace user-supplied JDBC URL to System.load() for native library loading
 * @kind path-problem
 * @problem.severity error
 * @id java/jdbc-url-to-system-load
 * @tags security
 *       external/cwe/cwe-094
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JdbcSystemLoadConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // JDBC connect() method url parameter
    exists(Method m, Parameter p |
      m.hasName("connect") and
      m.getDeclaringType().getASupertype*().hasQualifiedName("java.sql", "Driver") and
      p = m.getAParameter() and
      p.getType() instanceof TypeString and
      source.asParameter() = p
    )
    or
    // getURL() return values
    exists(MethodCall mc |
      mc.getMethod().hasName("getURL") and
      source.asExpr() = mc
    )
    or
    // SQLiteConfig or SQLiteDataSource setUrl/getUrl
    exists(MethodCall mc |
      (mc.getMethod().hasName("getUrl") or mc.getMethod().hasName("getDatabaseFilePath")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("load") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "System") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

