 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JdbcUrlSqlConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // JDBC connect() url parameter
    exists(Method m, Parameter p |
      m.hasName("connect") and
      m.getDeclaringType().getASupertype*().hasQualifiedName("java.sql", "Driver") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // getURL()
    exists(MethodCall mc |
      mc.getMethod().hasName("getURL") and
      source.asExpr() = mc
    )
