/**
 * @name JDBC URL to native library path taint flow
 * @description Trace taint from JDBC URL or system property to System.load() native library path
 * @kind path-problem
 * @problem.severity error
 * @id java/jdbc-url-native-library-taint
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking

module NativeLibTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // System.getProperty() - can be set by attacker via -D flags or programmatically
    exists(MethodCall mc |
      mc.getMethod().hasName("getProperty") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "System") and
      source.asExpr() = mc
    )
    or
    // JDBC URL parameter - connect(url, info)
    exists(Method m, Parameter p |
      (m.hasName("connect") or m.hasName("initialize") or m.hasName("loadNativeLibrary")) and
      m.getDeclaringType().hasQualifiedName("org.sqlite", "SQLiteJDBCLoader") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // JDBC Driver connect method
    exists(Method m, Parameter p |
      m.hasName("connect") and
      m.getDeclaringType().hasQualifiedName("org.sqlite", "JDBC") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("load") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "System") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

