/**
 * @name SQLiteConfig - dangerous pragma execution from user input
 * @description Check if user-controlled JDBC URL properties get passed as PRAGMA SQL statements
 * @kind path-problem
 * @problem.severity error
 * @id java/sqlite-pragma-injection
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module PragmaInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // JDBC connect url parameter
    exists(Method m, Parameter p |
      m.hasName("connect") and
      p = m.getAParameter() and
      p.getType() instanceof TypeString and
      source.asParameter() = p
    )
    or
    // getURL() call returns
    exists(MethodCall mc |
      mc.getMethod().hasName("getURL") and
      source.asExpr() = mc
    )
    or
    // Properties.getProperty() - JDBC connection properties
    exists(MethodCall mc |
      mc.getMethod().hasName("getProperty") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util", "Properties") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // NativeDB._exec or similar native SQL execution
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("_exec") or
        mc.getMethod().hasName("exec") or
        mc.getMethod().hasName("executeUpdate")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.sqlite.core", "DB") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Statement execute with string arg
    exists(MethodCall mc |
      mc.getMethod().hasName("execute") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.sql", "Statement") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

