/**
 * @name JDBC URL query parameter key injected into PRAGMA SQL statement
 * @description In SQLiteConfig.apply(), a 'pragma %s=%s' string is formatted with user-supplied key/value from JDBC URL
 * @kind path-problem
 * @problem.severity error
 * @id java/jdbc-url-pragma-key-injection
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module PragmaKeyInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // JDBC URL parameter from Driver.connect
    exists(Method m, Parameter p |
      m.hasName("connect") and
      m.getDeclaringType().hasQualifiedName("org.sqlite", "JDBC") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // Properties parameter passed to connect
    exists(Method m, Parameter p |
      m.hasName("connect") and
      m.getDeclaringType().hasQualifiedName("org.sqlite", "JDBC") and
      p = m.getAParameter() and
      p.getType().hasName("Properties") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // The format() call at line 219 building "pragma %s=%s" 
    exists(MethodCall mc |
      mc.getMethod().hasName("format") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "String") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.sqlite", "SQLiteConfig") and
      (sink.asExpr() = mc.getArgument(1) or sink.asExpr() = mc.getArgument(2))
    )
  }
}

module PragmaKeyInjectionFlow = TaintTracking::Global<PragmaKeyInjectionConfig>;
import PragmaKeyInjectionFlow::PathGraph

from PragmaKeyInjectionFlow::PathNode source, PragmaKeyInjectionFlow::PathNode sink
where PragmaKeyInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JDBC URL parameter $@ flows into 'pragma %s=%s' SQL format string - potential PRAGMA injection.", source.getNode(), "JDBC URL/properties"
